Response.Content:
{
	"jsonrpc": "2.0",
	"id": "unrealmcp-tools-list",
	"result":
	{
		"tools": [
			{
				"name": "list_actors",
				"description": "List actors in the current level with optional filtering by class, name, tag, or folder. Returns actor names, classes, transforms, and tags.",
				"inputSchema":
				{
					"type": "object",
					"properties":
					{
						"class_filter":
						{
							"type": "string"
						},
						"name_filter":
						{
							"type": "string"
						},
						"tag_filter":
						{
							"type": "string"
						},
						"folder_filter":
						{
							"type": "string"
						},
						"limit":
						{
							"type": "integer"
						}
					}
				},
				"annotations":
				{
					"readOnlyHint": true,
					"idempotentHint": true
				}
			},
			{
				"name": "create_actor",
				"description": "Spawn a new actor in the current level. Supports all standard UE actor classes including StaticMeshActor, PointLight, SpotLight, DirectionalLight, CameraActor, PlayerStart, etc.",
				"inputSchema":
				{
					"type": "object",
					"required": [
						"actor_class"
					],
					"properties":
					{
						"actor_class":
						{
							"type": "string"
						},
						"x":
						{
							"type": "number"
						},
						"y":
						{
							"type": "number"
						},
						"z":
						{
							"type": "number"
						},
						"pitch":
						{
							"type": "number"
						},
						"yaw":
						{
							"type": "number"
						},
						"roll":
						{
							"type": "number"
						},
						"scale_x":
						{
							"type": "number"
						},
						"scale_y":
						{
							"type": "number"
						},
						"scale_z":
						{
							"type": "number"
						},
						"label":
						{
							"type": "string"
						},
						"folder":
						{
							"type": "string"
						},
						"tags":
						{
							"type": "array",
							"items":
							{
								"type": "string"
							}
						}
					}
				}
			},
			{
				"name": "destroy_actors",
				"description": "Delete one or more actors from the current level by their label names.",
				"inputSchema":
				{
					"type": "object",
					"required": [
						"actor_names"
					],
					"properties":
					{
						"actor_names":
						{
							"type": "array",
							"items":
							{
								"type": "string"
							}
						}
					}
				},
				"annotations":
				{
					"destructiveHint": true
				}
			},
			{
				"name": "set_actor_transform",
				"description": "Set or modify the transform (position, rotation, scale) of an actor. Only provided fields are changed; omitted fields keep their current value.",
				"inputSchema":
				{
					"type": "object",
					"required": [
						"actor_name"
					],
					"properties":
					{
						"actor_name":
						{
							"type": "string"
						},
						"x":
						{
							"type": "number"
						},
						"y":
						{
							"type": "number"
						},
						"z":
						{
							"type": "number"
						},
						"pitch":
						{
							"type": "number"
						},
						"yaw":
						{
							"type": "number"
						},
						"roll":
						{
							"type": "number"
						},
						"scale_x":
						{
							"type": "number"
						},
						"scale_y":
						{
							"type": "number"
						},
						"scale_z":
						{
							"type": "number"
						},
						"relative":
						{
							"type": "boolean"
						}
					}
				},
				"annotations":
				{
					"idempotentHint": true
				}
			},
			{
				"name": "get_actor_properties",
				"description": "Read UPROPERTY values from an actor. Returns property names, types, and values. Use without property_names to discover available properties.",
				"inputSchema":
				{
					"type": "object",
					"required": [
						"actor_name"
					],
					"properties":
					{
						"actor_name":
						{
							"type": "string"
						},
						"property_names":
						{
							"type": "array",
							"items":
							{
								"type": "string"
							}
						}
					}
				},
				"annotations":
				{
					"readOnlyHint": true,
					"idempotentHint": true
				}
			},
			{
				"name": "set_actor_property",
				"description": "Set a UPROPERTY value on an actor. The value is provided as a string and parsed by the UE property system. Use get_actor_properties first to discover property names and current values.",
				"inputSchema":
				{
					"type": "object",
					"required": [
						"actor_name",
						"property_name",
						"property_value"
					],
					"properties":
					{
						"actor_name":
						{
							"type": "string"
						},
						"property_name":
						{
							"type": "string"
						},
						"property_value":
						{
							"type": "string"
						}
					}
				},
				"annotations":
				{
					"idempotentHint": true
				}
			},
			{
				"name": "select_actors",
				"description": "Select actors in the editor viewport by their labels. Useful for focusing on specific actors or preparing for batch operations.",
				"inputSchema":
				{
					"type": "object",
					"required": [
						"actor_names"
					],
					"properties":
					{
						"actor_names":
						{
							"type": "array",
							"items":
							{
								"type": "string"
							}
						},
						"add_to_selection":
						{
							"type": "boolean"
						}
					}
				},
				"annotations":
				{
					"idempotentHint": true
				}
			},
			{
				"name": "duplicate_actors",
				"description": "Duplicate actors with an optional positional offset. Multiple copies can be created, each offset incrementally from the previous.",
				"inputSchema":
				{
					"type": "object",
					"required": [
						"actor_names"
					],
					"properties":
					{
						"actor_names":
						{
							"type": "array",
							"items":
							{
								"type": "string"
							}
						},
						"offset_x":
						{
							"type": "number"
						},
						"offset_y":
						{
							"type": "number"
						},
						"offset_z":
						{
							"type": "number"
						},
						"copies":
						{
							"type": "integer"
						}
					}
				}
			},
			{
				"name": "set_actor_mobility",
				"description": "Set the mobility of an actor's root component (Static, Stationary, or Movable).",
				"inputSchema":
				{
					"type": "object",
					"required": [
						"actor_name",
						"mobility"
					],
					"properties":
					{
						"actor_name":
						{
							"type": "string"
						},
						"mobility":
						{
							"type": "string",
							"enum": [
								"Static",
								"Stationary",
								"Movable"
							]
						}
					}
				},
				"annotations":
				{
					"idempotentHint": true
				}
			},
			{
				"name": "attach_actor",
				"description": "Attach one actor to another as a child. The child actor will follow the parent's transform.",
				"inputSchema":
				{
					"type": "object",
					"required": [
						"actor_name",
						"parent_name"
					],
					"properties":
					{
						"actor_name":
						{
							"type": "string"
						},
						"parent_name":
						{
							"type": "string"
						},
						"socket_name":
						{
							"type": "string"
						},
						"attach_rule":
						{
							"type": "string",
							"enum": [
								"KeepRelative",
								"KeepWorld",
								"SnapToTarget"
							]
						}
					}
				},
				"annotations":
				{
					"idempotentHint": true
				}
			},
			{
				"name": "detach_actor",
				"description": "Detach an actor from its parent, making it a root-level actor again.",
				"inputSchema":
				{
					"type": "object",
					"required": [
						"actor_name"
					],
					"properties":
					{
						"actor_name":
						{
							"type": "string"
						},
						"keep_world_transform":
						{
							"type": "boolean"
						}
					}
				},
				"annotations":
				{
					"idempotentHint": true
				}
			},
			{
				"name": "get_actor_hierarchy",
				"description": "Get the parent-child hierarchy for an actor: its parent (if any) and all directly attached children.",
				"inputSchema":
				{
					"type": "object",
					"required": [
						"actor_name"
					],
					"properties":
					{
						"actor_name":
						{
							"type": "string"
						}
					}
				},
				"annotations":
				{
					"readOnlyHint": true,
					"idempotentHint": true
				}
			},
			{
				"name": "set_actor_hidden",
				"description": "Show or hide an actor in the editor viewport. Optionally propagates to attached children.",
				"inputSchema":
				{
					"type": "object",
					"required": [
						"actor_name",
						"hidden"
					],
					"properties":
					{
						"actor_name":
						{
							"type": "string"
						},
						"hidden":
						{
							"type": "boolean"
						},
						"propagate_to_children":
						{
							"type": "boolean"
						}
					}
				},
				"annotations":
				{
					"idempotentHint": true
				}
			},
			{
				"name": "set_actor_tags",
				"description": "Add, remove, or replace tags on an actor. Default mode is 'replace' which overwrites all existing tags.",
				"inputSchema":
				{
					"type": "object",
					"required": [
						"actor_name",
						"tags"
					],
					"properties":
					{
						"actor_name":
						{
							"type": "string"
						},
						"tags":
						{
							"type": "array",
							"items":
							{
								"type": "string"
							}
						},
						"mode":
						{
							"type": "string",
							"enum": [
								"replace",
								"add",
								"remove"
							]
						}
					}
				},
				"annotations":
				{
					"idempotentHint": true
				}
			},
			{
				"name": "focus_viewport",
				"description": "Focus the editor viewport camera on a specific actor or world position. Provide either actor_name or x/y/z coordinates.",
				"inputSchema":
				{
					"type": "object",
					"properties":
					{
						"actor_name":
						{
							"type": "string"
						},
						"x":
						{
							"type": "number"
						},
						"y":
						{
							"type": "number"
						},
						"z":
						{
							"type": "number"
						},
						"distance":
						{
							"type": "number"
						}
					}
				},
				"annotations":
				{
					"idempotentHint": true
				}
			},
			{
				"name": "set_viewport_camera",
				"description": "Set the editor viewport camera position and rotation directly.",
				"inputSchema":
				{
					"type": "object",
					"required": [
						"x",
						"y",
						"z"
					],
					"properties":
					{
						"x":
						{
							"type": "number"
						},
						"y":
						{
							"type": "number"
						},
						"z":
						{
							"type": "number"
						},
						"pitch":
						{
							"type": "number"
						},
						"yaw":
						{
							"type": "number"
						},
						"roll":
						{
							"type": "number"
						}
					}
				},
				"annotations":
				{
					"idempotentHint": true
				}
			},
			{
				"name": "take_screenshot",
				"description": "Capture the current editor viewport as an image. Returns a base64-encoded JPEG. Useful for visual verification of scene state.",
				"inputSchema":
				{
					"type": "object",
					"properties":
					{
						"width":
						{
							"type": "integer"
						},
						"height":
						{
							"type": "integer"
						},
						"quality":
						{
							"type": "integer"
						}
					}
				},
				"annotations":
				{
					"readOnlyHint": true,
					"idempotentHint": true
				}
			},
			{
				"name": "get_selection",
				"description": "Get the list of currently selected actors in the editor.",
				"inputSchema":
				{
					"type": "object",
					"properties":
					{
					}
				},
				"annotations":
				{
					"readOnlyHint": true,
					"idempotentHint": true
				}
			},
			{
				"name": "undo",
				"description": "Undo the last editor operation(s). Equivalent to Ctrl+Z.",
				"inputSchema":
				{
					"type": "object",
					"properties":
					{
						"count":
						{
							"type": "integer"
						}
					}
				}
			},
			{
				"name": "redo",
				"description": "Redo the last undone operation(s). Equivalent to Ctrl+Y.",
				"inputSchema":
				{
					"type": "object",
					"properties":
					{
						"count":
						{
							"type": "integer"
						}
					}
				}
			},
			{
				"name": "run_console_command",
				"description": "Execute an Unreal Engine console command. Useful for toggling debug visualizations, changing rendering settings, and more.",
				"inputSchema":
				{
					"type": "object",
					"required": [
						"command"
					],
					"properties":
					{
						"command":
						{
							"type": "string"
						}
					}
				}
			},
			{
				"name": "list_assets",
				"description": "List assets in the content browser with filtering by path, class, and name. Returns asset paths, classes, and file sizes.",
				"inputSchema":
				{
					"type": "object",
					"properties":
					{
						"path":
						{
							"type": "string"
						},
						"class_filter":
						{
							"type": "string"
						},
						"name_filter":
						{
							"type": "string"
						},
						"recursive":
						{
							"type": "boolean"
						},
						"limit":
						{
							"type": "integer"
						}
					}
				},
				"annotations":
				{
					"readOnlyHint": true,
					"idempotentHint": true
				}
			},
			{
				"name": "get_asset_info",
				"description": "Get detailed metadata about an asset: class, package, tags, size, references, and key properties.",
				"inputSchema":
				{
					"type": "object",
					"required": [
						"asset_path"
					],
					"properties":
					{
						"asset_path":
						{
							"type": "string"
						}
					}
				},
				"annotations":
				{
					"readOnlyHint": true,
					"idempotentHint": true
				}
			},
			{
				"name": "import_asset",
				"description": "Import a file from the filesystem into the content browser. Supports FBX, OBJ, PNG, JPG, WAV, and other standard formats.",
				"inputSchema":
				{
					"type": "object",
					"required": [
						"source_path",
						"destination_path"
					],
					"properties":
					{
						"source_path":
						{
							"type": "string"
						},
						"destination_path":
						{
							"type": "string"
						}
					}
				}
			},
			{
				"name": "delete_asset",
				"description": "Delete an asset from the content browser. By default checks for references to prevent breaking dependencies.",
				"inputSchema":
				{
					"type": "object",
					"required": [
						"asset_path"
					],
					"properties":
					{
						"asset_path":
						{
							"type": "string"
						},
						"check_references":
						{
							"type": "boolean"
						}
					}
				},
				"annotations":
				{
					"destructiveHint": true
				}
			},
			{
				"name": "duplicate_asset",
				"description": "Create a copy of an existing asset at a new location with a new name.",
				"inputSchema":
				{
					"type": "object",
					"required": [
						"source_path",
						"dest_path",
						"new_name"
					],
					"properties":
					{
						"source_path":
						{
							"type": "string"
						},
						"dest_path":
						{
							"type": "string"
						},
						"new_name":
						{
							"type": "string"
						}
					}
				}
			},
			{
				"name": "rename_asset",
				"description": "Rename or move an asset to a new path. Automatically fixes up references.",
				"inputSchema":
				{
					"type": "object",
					"required": [
						"asset_path",
						"new_path"
					],
					"properties":
					{
						"asset_path":
						{
							"type": "string"
						},
						"new_path":
						{
							"type": "string"
						}
					}
				},
				"annotations":
				{
					"idempotentHint": true
				}
			},
			{
				"name": "get_level_info",
				"description": "Get information about the currently loaded level: name, path, actor count, world settings, and streaming levels.",
				"inputSchema":
				{
					"type": "object",
					"properties":
					{
					}
				},
				"annotations":
				{
					"readOnlyHint": true,
					"idempotentHint": true
				}
			},
			{
				"name": "new_level",
				"description": "Create and open a new empty level at the specified content path.",
				"inputSchema":
				{
					"type": "object",
					"required": [
						"level_path"
					],
					"properties":
					{
						"level_path":
						{
							"type": "string"
						}
					}
				}
			},
			{
				"name": "open_level",
				"description": "Open an existing level in the editor.",
				"inputSchema":
				{
					"type": "object",
					"required": [
						"level_path"
					],
					"properties":
					{
						"level_path":
						{
							"type": "string"
						},
						"save_current":
						{
							"type": "boolean"
						}
					}
				},
				"annotations":
				{
					"idempotentHint": true
				}
			},
			{
				"name": "save_level",
				"description": "Save the current level and optionally all dirty packages.",
				"inputSchema":
				{
					"type": "object",
					"properties":
					{
						"save_all":
						{
							"type": "boolean"
						}
					}
				},
				"annotations":
				{
					"idempotentHint": true
				}
			},
			{
				"name": "get_world_settings",
				"description": "Read current world settings: gravity, kill-Z height, default game mode, navigation system class, and world bounds.",
				"inputSchema":
				{
					"type": "object",
					"properties":
					{
					}
				},
				"annotations":
				{
					"readOnlyHint": true,
					"idempotentHint": true
				}
			},
			{
				"name": "set_world_settings",
				"description": "Modify world settings for the current level. Set gravity, kill-Z height, default game mode, and world bounds checks. Only provided fields are changed.",
				"inputSchema":
				{
					"type": "object",
					"properties":
					{
						"gravity_z":
						{
							"type": "number"
						},
						"kill_z":
						{
							"type": "number"
						},
						"game_mode_class":
						{
							"type": "string"
						},
						"enable_world_bounds_checks":
						{
							"type": "boolean"
						}
					}
				},
				"annotations":
				{
					"idempotentHint": true
				}
			},
			{
				"name": "create_material",
				"description": "Create a new Material asset with specified shading model and blend mode. The material is saved and ready for parameter editing.",
				"inputSchema":
				{
					"type": "object",
					"required": [
						"asset_path"
					],
					"properties":
					{
						"asset_path":
						{
							"type": "string"
						},
						"shading_model":
						{
							"type": "string",
							"enum": [
								"DefaultLit",
								"Unlit",
								"Subsurface",
								"ClearCoat",
								"TwoSidedFoliage"
							]
						},
						"blend_mode":
						{
							"type": "string",
							"enum": [
								"Opaque",
								"Masked",
								"Translucent",
								"Additive"
							]
						},
						"two_sided":
						{
							"type": "boolean"
						}
					}
				}
			},
			{
				"name": "create_material_instance",
				"description": "Create a Material Instance Constant from a parent material. Parameters can then be set using set_material_scalar/set_material_vector.",
				"inputSchema":
				{
					"type": "object",
					"required": [
						"asset_path",
						"parent_path"
					],
					"properties":
					{
						"asset_path":
						{
